final:
module RefModule (  
    input wire [23:0] adc_input,  
    input wire enable,  
    output reg [11:0] adc_output  
);  
  wire [23:0] _tap_adc_input = adc_input & {24{1'b1}};

    always @(*) begin  
        if (enable)  
            adc_output = adc_input[11:0];  
        else  
            adc_output = adc_output; // retain last output  
    end  
endmodule
